package com.bookmyticket.config;
import com.bookmyticket.entity.*; import com.bookmyticket.repository.*; import lombok.RequiredArgsConstructor; import org.springframework.boot.CommandLineRunner; import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; import org.springframework.stereotype.Component; import java.math.BigDecimal; import java.time.*;
@Component @RequiredArgsConstructor
public class DataSeeder implements CommandLineRunner { private final UserRepository users; private final AdminRepository admins; private final MovieRepository movies; private final TheaterRepository theaters; private final ShowRepository shows; private final SeatRepository seats; private final BCryptPasswordEncoder encoder;
 public void run(String... args){ if(users.findByMobile("9123456789").isEmpty()) users.save(User.builder().mobile("9123456789").name("Default User").password(encoder.encode("@123654")).build()); if(admins.findByUsername("admin").isEmpty()) admins.save(Admin.builder().username("admin").name("Administrator").password(encoder.encode("admin@123")).build());
 if(movies.count()==0){ Movie m1=movies.save(Movie.builder().name("Kantara Chapter 1").description("Action drama movie available for booking.").language("Kannada").genre("Action/Drama").duration("2h 45m").releaseDate(LocalDate.now()).posterImageUrl("https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?w=600").status(MovieStatus.ACTIVE).build()); Movie m2=movies.save(Movie.builder().name("Java City").description("A tech thriller for students and developers.").language("English").genre("Thriller").duration("2h 10m").releaseDate(LocalDate.now()).posterImageUrl("https://images.unsplash.com/photo-1517604931442-7e0c8ed2963c?w=600").status(MovieStatus.ACTIVE).build()); Theater t=theaters.save(Theater.builder().name("PVR Orion Mall").city("Bengaluru").address("Rajajinagar, Bengaluru").build()); shows.save(Show.builder().movie(m1).theater(t).showDate(LocalDate.now().plusDays(1)).showTime(LocalTime.of(18,30)).price(new BigDecimal("180.00")).build()); shows.save(Show.builder().movie(m2).theater(t).showDate(LocalDate.now().plusDays(1)).showTime(LocalTime.of(21,30)).price(new BigDecimal("220.00")).build()); for(char r='A'; r<='F'; r++){ for(int n=1;n<=10;n++){ seats.save(Seat.builder().theater(t).seatNumber(""+r+n).status(SeatStatus.AVAILABLE).build()); } } } }
}
